public class CacheSimulation {
    private int[] cacheData;
    private boolean[] valid;
    private boolean[] dirty;
    private int[] tags;
    private int cacheSize;
    private boolean writeThrough;

    public CacheSimulation(int size, boolean writeThrough) {
        this.cacheSize = size;
        this.writeThrough = writeThrough;
        cacheData = new int[size];
        valid = new boolean[size];
        dirty = new boolean[size];
        tags = new int[size];
    }

    public void write(int address, int data) {
        int index = address % cacheSize;

        if (writeThrough) {
            // Write to both cache AND main memory
            cacheData[index] = data;
            valid[index] = true;
            dirty[index] = false;  // Clean (not modified)
            writeToMainMemory(address, data);
        } else {
            // Write-back: write to cache only
            cacheData[index] = data;
            valid[index] = true;
            dirty[index] = true;   // Mark as modified/dirty
            tags[index] = address / cacheSize;
        }
    }

    public int read(int address) {
        int index = address % cacheSize;
        int tag = address / cacheSize;

        if (valid[index] && tags[index] == tag) {
            return cacheData[index]; // Cache hit
        }

        // Cache miss - load from memory
        int data = readFromMainMemory(address);
        if (dirty[index]) {
            // Write back modified data before replacing
            writeToMainMemory(address, cacheData[index]);
        }
        cacheData[index] = data;
        valid[index] = true;
        dirty[index] = false;
        tags[index] = tag;
        return data;
    }

    private void writeToMainMemory(int addr, int data) {
